import requests

# Mock API endpoint - replace with actual API URL
def get_ahab_albums():
    api_url = "https://api.musicdb.example.com/bands/Ahab/albums"
    response = requests.get(api_url)
    if response.status_code == 200:
        albums = response.json()
        discography = {}
        for album in albums:
            year = album['release_year']
            if year not in discography:
                discography[year] = []
            discography[year].append(album['title'])
        return discography
    else:
        return None

# Example usage
ahab_albums = get_ahab_albums()
print(ahab_albums)
